import React, { useState, useEffect } from 'react';
import { fetchUSDailyData } from '../../../../api';
import { Line } from 'react-chartjs-2';
import styles from './StateChart.module.css';

const StateChart = ({ data: stateData, state }) => {
	const [dailyData, setDailyData] = useState([]);

	useEffect(() => {
		const fetchAPI = async () => {
			setDailyData(await fetchUSDailyData());
		}

		fetchAPI();
	}, []);

	const initialLineChart = (
		dailyData.length
			? (
				<Line
					data={{
						labels: dailyData.map(({ date }) => date),
						datasets: [{
							data: dailyData.map((data) => data.confirmed),
							label: 'Infected',
							borderColor: '#3333ff',
							backgroundColor: 'rgba(0, 0, 255, 0.1)',
							fill: true
						}, {
							data: dailyData.map((data) => data.deaths),
							label: 'Deaths',
							borderColor: 'red',
							backgroundColor: 'rgba(255, 0, 0, 0.3)',
							fill: true
						},  {
				            data: dailyData.map((data) => data.recovered),
				            label: 'Recovered',
				            borderColor: 'green',
				            backgroundColor: 'rgba(0, 255, 0, 0.5)',
				            fill: true
						}]
					}}
			/>) : null
	);

	const secondlineChart = (
		stateData.length
			? (
				<Line
					data={{
						labels: stateData.map(({ date }) => date),
						datasets: [{
							data: stateData.map(({ confirmed }) => confirmed),
							label: 'Infected',
							borderColor: '#3333ff',
							backgroundColor: 'rgba(0, 0, 255, 0.1)',
							fill: true
						}, {
							data: stateData.map(({ deaths }) => deaths),
							label: 'Deaths',
							borderColor: 'red',
							backgroundColor: 'rgba(255, 0, 0, 0.3)',
							fill: true
						}]
					}}
			/>) : null
	);

	return (
		<div className={styles.container}>
			{state ? secondlineChart : initialLineChart}
		</div>
	)
}

export default StateChart;
